class Solution:
    def minFlips(self, s):
        n = len(s)
        t = s + s
        cost0 = cost1 = 0
        best = n
        for i in range(n):
            exp = i % 2
            if int(t[i]) != exp:
                cost0 += 1
            else:
                cost1 += 1
        best = min(cost0, cost1)
        for i in range(n, 2 * n):
            l = i - n
            expL = l % 2
            if int(t[l]) != expL:
                cost0 -= 1
            else:
                cost1 -= 1
            expR = i % 2
            if int(t[i]) != expR:
                cost0 += 1
            else:
                cost1 += 1
            best = min(best, cost0, cost1)
        return best

