var minFlips = function(s) {
    const n = s.length;
    const t = s + s;
    let cost0 = 0, cost1 = 0;
    for (let i = 0; i < n; i++) {
        const exp = i % 2;
        if ((t.charCodeAt(i) - 48) !== exp) cost0++; else cost1++;
    }
    let best = Math.min(cost0, cost1);
    for (let i = n; i < 2 * n; i++) {
        const l = i - n;
        const expL = l % 2;
        if ((t.charCodeAt(l) - 48) !== expL) cost0--; else cost1--;
        const expR = i % 2;
        if ((t.charCodeAt(i) - 48) !== expR) cost0++; else cost1++;
        best = Math.min(best, cost0, cost1);
    }
    return best;
};
